args.CommandLine:
"$logPath = "C:\Users\user\.gemini\antigravity\brain\c1ec9a64-6773-4fe2-b394-4f6f79b25e73\.system_generated\logs\transcript.jsonl"
$lines = Get-Content $logPath -Encoding UTF8
$matchedLines = $lines | Where-Object { $_ -match 'view_file' -and $_ -match 'app\.js' -and $_ -match 'class Store' }
if ($matchedLines.Count -gt 0) {
    Write-Output "Found app.js in tool response!"
    $obj = $matchedLines[-1] | ConvertFrom-Json
    # Try to find the file content inside $obj
    # Usually tool responses have an 'output' field or are in 'content'
    # We will just write the JSON string representation to a file and parse it
    $obj | ConvertTo-Json -Depth 10 | Out-File "C:\temp_appjs_log.json" -Encoding UTF8
    Write-Output "Saved to C:\temp_appjs_log.json"
} else {
    Write-Output "Not found."
}"
